#include <stdio.h>
#include <stdlib.h>

int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int **B = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            B[i] = (int *)malloc(N * sizeof(int));
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                scanf("%d", &B[i][j]);
            }
        }
        int **A = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            A[i] = (int *)malloc(N * sizeof(int));
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                A[i][j] = 0;
            }
        }
        int flag = 1;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (B[i][j] != 0) {
                    if (i == j) {
                        A[i][j] = 1;
                    } else {
                        A[i][j] = -1;
                        A[j][i] = -1;
                    }
                }
            }
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                int sum = 0;
                for (int k = 0; k < N; k++) {
                    sum += A[i][k] * A[j][k];
                }
                if (sum != B[i][j]) {
                    flag = 0;
                    break;
                }
            }
            if (!flag) break;
        }
        if (flag) {
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    printf("%d ", A[i][j]);
                }
                printf("\n");
            }
        } else {
            printf("-1\n");
        }
        for (int i = 0; i < N; i++) {
            free(B[i]);
            free(A[i]);
        }
        free(B);
        free(A);
    }
    return 0;
}

